macro.implementation:
do {
  (canp)->tx_mailbox_mask |= (canmbxmask_t)((flags) & 0xFFFFU);
  (canp)->tx_error_mask   |= (canmbxmask_t)(((flags) >> 16U) & 0xFFFFU);
  (canp)->events          |= CAN_EVENT_TX;
  osalSysLockFromISR();
  osalThreadDequeueAllI(&(canp)->txqueue, MSG_OK);
  osalSysUnlockFromISR();
  __cbdrv_invoke_cb(canp);
} while (false)

do {
  (canp)->rx_mailbox_mask |= (canmbxmask_t)(flags);
  (canp)->events          |= CAN_EVENT_RX;
  osalSysLockFromISR();
  osalThreadDequeueAllI(&(canp)->rxqueue, MSG_OK);
  osalSysUnlockFromISR();
  __cbdrv_invoke_cb(canp);
} while (false)

objinit.implementation:
self->events          = 0U;
self->rx_mailbox_mask = 0U;
self->tx_mailbox_mask = 0U;
self->tx_error_mask   = 0U;
self->errors          = 0U;
#if CAN_USE_SYNCHRONIZATION == TRUE
osalThreadQueueObjectInit(&self->txqueue);
osalThreadQueueObjectInit(&self->rxqueue);
#endif

#if defined(CAN_DRIVER_EXT_INIT_HOOK)
CAN_DRIVER_EXT_INIT_HOOK(self);
#endif

method.implementation:
osalDbgCheckClassI();
osalDbgCheck((self != NULL) && (ctfp != NULL) &&
             (mailbox <= (canmbx_t)CAN_TX_MAILBOXES));
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == CAN_SLEEP),
              "invalid state");

if (!can_lld_is_tx_empty(self, mailbox)) {
  return true;
}

can_lld_transmit(self, mailbox, ctfp);

return false;

osalDbgCheckClassI();
osalDbgCheck((self != NULL) && (crfp != NULL) &&
             (mailbox <= (canmbx_t)CAN_RX_MAILBOXES));
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == CAN_SLEEP),
              "invalid state");

if (!can_lld_is_rx_nonempty(self, mailbox)) {
  return true;
}

can_lld_receive(self, mailbox, crfp);

return false;

osalDbgCheck((self != NULL) && (ctfp != NULL) &&
             (mailbox <= (canmbx_t)CAN_TX_MAILBOXES));

osalSysLock();
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == CAN_SLEEP),
              "invalid state");

while ((self->state == CAN_SLEEP) || !can_lld_is_tx_empty(self, mailbox)) {
  msg_t msg = osalThreadEnqueueTimeoutS(&self->txqueue, timeout);
  if (msg != MSG_OK) {
    osalSysUnlock();
    return msg;
  }
}

can_lld_transmit(self, mailbox, ctfp);
osalSysUnlock();

return MSG_OK;

osalDbgCheck((self != NULL) && (crfp != NULL) &&
             (mailbox <= (canmbx_t)CAN_RX_MAILBOXES));

osalSysLock();
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == CAN_SLEEP),
              "invalid state");

while ((self->state == CAN_SLEEP) || !can_lld_is_rx_nonempty(self, mailbox)) {
  msg_t msg = osalThreadEnqueueTimeoutS(&self->rxqueue, timeout);
  if (msg != MSG_OK) {
    osalSysUnlock();
    return msg;
  }
}

can_lld_receive(self, mailbox, crfp);
osalSysUnlock();

return MSG_OK;

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == CAN_SLEEP),
              "invalid state");
if (self->state == HAL_DRV_STATE_READY) {
  can_lld_sleep(self);
  self->state = CAN_SLEEP;
  self->events |= CAN_EVENT_SLEEP;
}
osalSysUnlock();

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == CAN_SLEEP),
              "invalid state");
if (self->state == CAN_SLEEP) {
  can_lld_wakeup(self);
  self->state = HAL_DRV_STATE_READY;
  self->events |= CAN_EVENT_WAKEUP;
}
osalSysUnlock();

can_events_t events;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
events = self->events & mask;
self->events &= ~mask;
osalSysRestoreStatusX(sts);

return events;

canmbxmask_t mask;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
mask = self->rx_mailbox_mask;
self->rx_mailbox_mask = 0U;
osalSysRestoreStatusX(sts);

return mask;

canmbxmask_t mask;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
mask = self->tx_mailbox_mask;
self->tx_mailbox_mask = 0U;
osalSysRestoreStatusX(sts);

return mask;

canmbxmask_t mask;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
mask = self->tx_error_mask;
self->tx_error_mask = 0U;
osalSysRestoreStatusX(sts);

return mask;

canerror_t errors;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
errors = self->errors;
self->errors = 0U;
osalSysRestoreStatusX(sts);

return errors;

msg_t msg;

if (config != NULL) {
  self->config = __can_setcfg_impl(self, config);
  if (self->config == NULL) {
    return HAL_RET_CONFIG_ERROR;
  }
}

msg = can_lld_start(self);
if (msg != HAL_RET_SUCCESS) {
  self->config = NULL;
  self->events = 0U;
  self->rx_mailbox_mask = 0U;
  self->tx_mailbox_mask = 0U;
  self->tx_error_mask = 0U;
  self->errors = 0U;
}

return msg;

can_lld_stop(self);
can_lld_reset(self);
#if CAN_USE_SYNCHRONIZATION == TRUE
osalThreadDequeueAllI(&self->rxqueue, MSG_RESET);
osalThreadDequeueAllI(&self->txqueue, MSG_RESET);
osalOsRescheduleS();
#endif
